    if (result == OP_SUCCESS) {
        printk("[USER:%s] System status: %s\n", user_id.name, resp.data);
    } else {
        printk("[USER:%s] Status request failed: %d\n", user_id.name, result);
    }

    k_sleep(K_MSEC(200));

    /* ---- Test 2: Read a public config (should succeed) ---- */
    printk("\n=== Test 2: Read Public Config (requires READ) ===\n");
    memset(&req, 0, sizeof(req));
    req.operation = OP_CONFIG_READ;
    strncpy((char *)req.data, "system.hostname", sizeof(req.data) - 1);
    req.data_len = strlen((char *)req.data) + 1;
    result = send_priv_request(&user_id, &req, &resp);
    if (result == OP_SUCCESS) {
        printk("[USER:%s] Config 'system.hostname' = '%s'\n", user_id.name, resp.data);
    } else {
        printk("[USER:%s] Config read failed: %d\n", user_id.name, result);
    }

    k_sleep(K_MSEC(200));

    /* ---- Test 3: Read admin-only config (should be DENIED) ---- */
    printk("\n=== Test 3: Read Admin Config (requires ADMIN - should DENY) ===\n");
    memset(&req, 0, sizeof(req));
    req.operation = OP_CONFIG_READ;
    strncpy((char *)req.data, "admin.secret_key", sizeof(req.data) - 1);
    req.data_len = strlen((char *)req.data) + 1;
    result = send_priv_request(&user_id, &req, &resp);
    if (result == OP_DENIED) {
        printk("[USER:%s] As expected, reading 'admin.secret_key' was DENIED\n", user_id.name);
    } else if (result == OP_SUCCESS) {
        printk("[USER:%s] SECURITY ISSUE: Read admin config! value='%s'\n", user_id.name, resp.data);
    }

    k_sleep(K_MSEC(200));

    /* ---- Test 4: Request flash write via admin escalation (should succeed) ---- */
    printk("\n=== Test 4: Flash Write via Admin Escalation ===\n");
    memset(&req, 0, sizeof(req));
    req.operation = OP_FLASH_WRITE;
