    memcpy(req.data, user_data, sizeof(user_data));
    req.data_len = sizeof(user_data);
    result = send_priv_request(&user_id, &req, &resp);
    if (result == OP_SUCCESS) {
        printk("[USER:%s] Flash write succeeded via admin escalation!\n", user_id.name);
    } else {
        printk("[USER:%s] Flash write result: %d\n", user_id.name, result);
    }

    k_sleep(K_MSEC(200));

    /* ---- Test 5: Request config modification via admin (should succeed) ---- */
    printk("\n=== Test 5: Config Modify via Admin Escalation ===\n");
    memset(&req, 0, sizeof(req));
    req.operation = OP_CONFIG_MODIFY;
